sql:
SELECT v.description, v.phone_number
FROM violations v
WHERE v.area_code = 917 AND v.subject_id = 1 AND v.description LIKE '%spam%';

SELECT DISTINCT phone_number
FROM violations
WHERE recorded = 'Yes';

SELECT (
  CAST(SUM(CASE WHEN recorded = 'Yes' THEN 1 ELSE 0 END) AS REAL) * 100 / 
  COUNT(violation_id)
) AS percentage_recorded
FROM violations;

SELECT DISTINCT s.state_name
FROM violations v
JOIN states s ON v.state_id = s.state_id;

SELECT c.complaint_id, v.area_code, c.status
FROM complaints c
LEFT JOIN violations v ON c.violation_id = v.violation_id;

SELECT s.subject_name, s.subject_description 
FROM subjects s 
WHERE EXISTS (SELECT 1 FROM violations v WHERE v.subject_id = s.subject_id);
